    <> (case msg.exemplarValue of
      Nothing -> mempty
      Just (Exemplar'Value'AsDouble v) -> archDouble 25 v
      Just (Exemplar'Value'AsInt v) -> archFixed64 49 (fromIntegral v))
    <> (if BS.null msg.exemplarSpanId then mempty else archBytes 34 msg.exemplarSpanId)
    <> (if BS.null msg.exemplarTraceId then mempty else archBytes 42 msg.exemplarTraceId)
    <> encodeUnknownFields msg.exemplarUnknownFields

