  messageSize msg =
    (V.foldl' (\acc v -> acc + archSubmessageSize (messageSize v)) 0 msg.exemplarFilteredAttributes)
    + (if msg.exemplarTimeUnixNano == 0 then 0 else archFixed64Size)
    + (case msg.exemplarValue of { Nothing -> 0; Just (Exemplar'Value'AsDouble v) -> archFixed64Size
    ; Just (Exemplar'Value'AsInt v) -> archFixed64Size })
    + (if BS.null msg.exemplarSpanId then 0 else archBytesSize msg.exemplarSpanId)
    + (if BS.null msg.exemplarTraceId then 0 else archBytesSize msg.exemplarTraceId)
    + unknownFieldsSize msg.exemplarUnknownFields

