        (pure (Exemplar {exemplarFilteredAttributes = acc_0, exemplarTimeUnixNano = acc_1, exemplarValue = acc_2, exemplarSpanId = acc_3, exemplarTraceId = acc_4, exemplarUnknownFields = reverse acc_unknown_}))
        (\fn wt -> case fn of
