            loop acc_0 acc_1 (Just (Exemplar'Value'AsDouble v)) acc_3 acc_4 acc_unknown_
          6 -> do
            v <- (fromIntegral <$> decodeFieldFixed64)
            loop acc_0 acc_1 (Just (Exemplar'Value'AsInt v)) acc_3 acc_4 acc_unknown_
          4 -> do
            v <- decodeFieldBytes
            loop acc_0 acc_1 acc_2 v acc_4 acc_unknown_
          5 -> do
            v <- decodeFieldBytes
            loop acc_0 acc_1 acc_2 acc_3 v acc_unknown_
